import re
from collections import defaultdict


def parse_requirements(req_text):
    results = []
    for line in req_text.strip().splitlines():
        line = line.strip()
        if not line or line.startswith('#'):
            continue
        match = re.match(r'^([a-zA-Z0-9_-]+)\s*(==|>=|<=|~=|!=|>|<)\s*(.+)$', line)
        if match:
            results.append({
                'name': match.group(1).lower(),
                'operator': match.group(2),
                'version': match.group(3).strip()
            })
        else:
            results.append({
                'name': line.lower(),
                'operator': None,
                'version': None
            })
    return results


def check_version_conflict(req_text):
    parsed = parse_requirements(req_text)
    pkg_versions = defaultdict(list)
    for p in parsed:
        if p['operator'] and p['version']:
            pkg_versions[p['name']].append(f"{p['operator']}{p['version']}")

    conflicts = []
    for pkg, versions in sorted(pkg_versions.items()):
        unique = list(dict.fromkeys(versions))  # preserve order, deduplicate
        if len(unique) > 1:
            conflicts.append({'package': pkg, 'versions': unique})

    return conflicts


def find_outdated(current, latest):
    outdated = []
    for pkg in sorted(current):
        if pkg in latest:
            cur_parts = tuple(int(x) for x in current[pkg].split('.'))
            lat_parts = tuple(int(x) for x in latest[pkg].split('.'))
            if cur_parts < lat_parts:
                outdated.append({
                    'name': pkg,
                    'current': current[pkg],
                    'latest': latest[pkg]
                })
    return outdated


def generate_requirements(packages_dict):
    lines = []
    for name in sorted(packages_dict):
        version = packages_dict[name]
        if version is None:
            lines.append(name)
        else:
            lines.append(f'{name}=={version}')
    return '\n'.join(lines)
